var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"......잠깐.","JPN":"……お待ちください。","ENG":"Wait.","TWN":"……等等。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"부서진 네임리스 원의 고치 안에서 침식파와는 다른 이질적인 에너지가 느껴집니다!","JPN":"壊れたネームレスワンの繭の中から、侵食波とは違う異質なエネルギーが感じられます！","ENG":"I can feel an energy inside the broken cocoon! It's different from the Corruption ray!","TWN":"在無名1破碎的卵囊中，我感受到了與侵蝕波不同的其他能量反應！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"위험할지도 모르니 물러서세요, 부사령관님!","JPN":"危険かもしれません。下がってください、副司令官！","ENG":"Stay back, Deputy Commander. It might be dangerous!","TWN":"可能會有危險。請先退後，副司令官大人！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"과연...... 듣던대로 아주 인상적인 방식이네요.","JPN":"なるほど……聞いていたとおり、とても印象的なやり方ですね。","ENG":"Hmm... It's an interesting method, like I heard.","TWN":"果然…… 就如同傳說的那樣，真是令人印象深刻的方式。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"뭐라고? 넌 저 고치 안에 뭐가 있는지 알고 있는 건가?","JPN":"何だと？　お前はあの繭の中に何があるのか知ってるのか？","ENG":"What? Do you know what's inside that cocoon?","TWN":"你說什麼？你知道那個卵囊裡有什麼嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아니요, 사실 정확히는 모릅니다.","JPN":"いいえ、正確にはわかりません。","ENG":"No, not exactly.","TWN":"不，我其實並不是很清楚。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그저 아주 대단하신 분께 대강의 이야기를 전해 들었을 뿐이죠.","JPN":"ただ、とてもすごい方から、大体の話を聞いただけです。","ENG":"But I heard a rough story from a remarkable person.","TWN":"我只是聽一位很偉大的人講述過大致的故事。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"대단하신 분? 네가 그렇게 부를만한 사람이 있었나?","JPN":"すごい方？　お前がそんな風に呼ぶほどの人がいるのか？","ENG":"A remarkable person? Who could it be?","TWN":"偉大的人？還能有人有資格讓你那樣稱呼？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"한때 제 상관이었던 분입니다.","JPN":"かつて、僕の上官だった人です。","ENG":"My former boss.","TWN":"那位是我以前的上司。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"세상의 모든 슬픔을 경험한...... 아주 불쌍한 분이죠.","JPN":"この世のあらゆる悲しみを経験した……とても可哀想な方です。","ENG":"A poor soul... who has experienced all the sorrow in the world.","TWN":"經歷了世界上所有悲傷的…… 非常可憐的人。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......무슨 말인지 모르겠군.","JPN":"……何を言っているんだか、さっぱりわからないな。","ENG":"I don't understand what you're talking about.","TWN":"……不知道你在說什麼。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"하여간 넌 저 고치 안에서 무슨 일이 벌어지는지 짐작하고 있다는 뜻이겠지?","JPN":"とにかく、お前はあの繭の中で何が起こっているのか推測できるということだろう？","ENG":"Anyways, it means you can guess what's happening inside that cocoon, right?","TWN":"總之，意思就是你猜到那個卵囊裡到底在發生什麼，對吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"네. 제 추측이 맞다면 저건 아마도 아주 오랜 과거로부터 온 선물일 겁니다.","JPN":"はい。僕の推測が正しければ、あれはおそらくいにしえからの贈り物です。","ENG":"Yes. If my guess is correct, it's a gift from the past.","TWN":"是的。如果我的推測正確，那可能就是從更加遙遠的從前所送來的禮物。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"선물이라고?","JPN":"贈り物だと？","ENG":"A gift?","TWN":"禮物？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그래요. 네임리스 원은 애초에 저걸 전달하기 위한 살아있는 포장지였던 셈이죠.","JPN":"ええ。ネームレスワンはあれを届けるための、生きた包装紙だったのでしょう。","ENG":"Yes. The Nameless One was in fact a living package, created to deliver that gift.","TWN":"是啊。無名1從一開始就是為了送達這個禮物而活著的包裝紙而已。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 그 포장을 풀 <color=#ffd34c>자격</color>을 가진 자만이 <color=#ffd34c>선물</color>을 꺼낼 수 있도록 설계되어 있었던 겁니다.","JPN":"そして、その包装を開ける<color=#ffd34c>資格</color>を持つ者のみ<color=#ffd34c>プレゼント</color>を取り出せるように設計されているのでしょう。","ENG":"It was designed so that only a <color=#ffd34c>worthy</color> person could open the <color=#ffd34c>gift</color>.","TWN":"還有，為了只讓有<color=#ffd34c>資格</color>打開包裝的人取出<color=#ffd34c>禮物</color>，所以才設計成這樣。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"놈을 쓰러트릴 힘이 없다면, 어차피 선물을 얻게 되더라도 그걸 감당하지 못할 거란 뜻이겠죠.","JPN":"奴を倒せる力がなければ、プレゼントを手に入れたとしても扱いきれないということです。","ENG":"It probably means that if you can't handle the monster, you can't handle the gift either.","TWN":"也就是說如果沒有打敗它的力量，就算獲得禮物也無法承受。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"터무니없군. 그 5종 침식체가...... 누군가에 의해 의도적으로 보내진 거라고?","JPN":"とんでもない話だな。あの第5種侵食体が、誰かによって意図的に送られたものだと？","ENG":"You're talking nonsense. That Category 5 C.O. was sent by someone on purpose?","TWN":"真是荒謬。那5類侵蝕體是…… 被某人故意送過來的？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그런 짓을 벌인 이유가 고작...... 무언가를 전달하기 위해서라니.","JPN":"そんなことをした理由が、たかが……何かを届けるためだなんて。","ENG":"And whoever did it just wanted to deliver something?","TWN":"做這種事的理由僅僅…… 是為了傳達某樣東西？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};